import java.io.IOException;
import java.io.PrintWriter;
import javax.servlet.http.HttpServlet;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;

public class SecureServlet extends HttpServlet {

    protected void doGet(HttpServletRequest request, HttpServletResponse response) throws IOException {
        String userInput = request.getParameter("input");
        PrintWriter out = response.getWriter();

        out.println("<html>");
        out.println("<head><title>Secure Page</title></head>");
        out.println("<body>");
        out.println("<h1>Hello, " + encodeForHtml(userInput) + "</h1>"); // Encode user input before embedding in HTML
        out.println("</body>");
        out.println("</html>");
    }

    private String encodeForHtml(String input) {
        if (input == null) {
            return "";
        }
        return org.owasp.esapi.ESAPI.encoder().encodeForHTML(input);
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
